def integrand(t): """ The function inside the integral: (t^4 * e^t) / (e^t - 1)^2 """ # Prevent division by zero error when t is extremely close to 0. # Mathematically, the limit of this function as t -&gt; 0 is 0. if t &lt; 1e-10: return 0.0 try: # Calculate the numerator and denominator numerator = (t**4) * np.exp(t) denominator = (np.exp(t) - 1)**2 return numerator / denominator except OverflowError: # Handle cases where exp(t) might be too large (though unlikely in this range) return 0.0 def debye_function(x): """ Calculates D(x) = 3 * x^3 * Integral from 0 to 1/x """ # 1. Calculate the integration coefficient: 3 * x^3 coef = 3 * (x**3) # 2. Determine the upper limit of integration: 1/x upper_limit = 1.0 / x # 3. Perform the definite integral using Gaussian quadrature (quad) # quad returns a tuple (value, error), we only need the value [0] integral_result, _ = quad(integrand, 0, upper_limit) # 4. Return the final result return coef * integral_result # ==========================================
# Main Execution &amp; Output
# ========================================== # Generate a list of x values linearly spaced between x_start and x_end
x_values = np.linspace(x_start, x_end, num_points)
